// Merge gap windows with market data
const gaps   = $('Load Gap Windows').all().map(i => i.json);
const mktRow = $('Load Market Data').first()?.json || {};

const marketMedian = mktRow.market_median ? Number(mktRow.market_median) : null;
const marketMin    = mktRow.market_min    ? Number(mktRow.market_min)    : null;
const marketMax    = mktRow.market_max    ? Number(mktRow.market_max)    : null;
const marketAvg    = mktRow.market_avg    ? Number(mktRow.market_avg)    : null;
const hasMarket    = marketMedian !== null;

const recs = [];

for (const g of gaps) {
  const base   = g.base_price ? Number(g.base_price) : null;
  const nights = Number(g.nights);
  let recommended, recType, reason, confidence;

  if (nights === 1) {
    recType  = 'gap_special_price';
    reason   = 'Короткое окно 1 ночь: лучше продать спецценой, чем оставить пустым.';
    if (hasMarket && base) {
      recommended = Math.max(base * 0.85, marketMedian * 0.80);
      confidence  = 0.70;
    } else if (base) {
      recommended = base * 0.85;
      confidence  = 0.45;
    } else continue;
  } else if (nights === 2) {
    recType  = 'gap_special_price';
    reason   = 'Окно 2 ночи: можно продать коротким заездом со сниженной ценой.';
    if (hasMarket && base) {
      recommended = Math.max(base * 0.90, marketMedian * 0.90);
      confidence  = 0.70;
    } else if (base) {
      recommended = base * 0.90;
      confidence  = 0.45;
    } else continue;
  } else {
    recType  = 'gap_special_price';
    reason   = 'Окно 3 ночи: можно продавать как короткий заезд без сильной скидки.';
    if (hasMarket && base) {
      recommended = Math.max(base, marketMedian * 0.95);
      confidence  = 0.65;
    } else if (base) {
      recommended = base * 0.95;
      confidence  = 0.50;
    } else continue;
  }

  // Override: raise_price if market >> base
  if (hasMarket && base && marketMedian > base * 1.20) {
    recType    = 'raise_price';
    recommended = Math.round(marketMedian * 0.90);
    reason     = `Рынок (₽${Math.round(marketMedian)}) заметно выше базовой цены (₽${Math.round(base)}). Рекомендуем повысить цену.`;
    confidence  = 0.65;
  }
  // Override: lower_price if market << base
  if (hasMarket && base && marketMedian < base * 0.80) {
    recType    = 'lower_price';
    recommended = Math.round(marketMedian * 1.05);
    reason     = `Рынок (₽${Math.round(marketMedian)}) ниже базовой цены (₽${Math.round(base)}). Есть риск простоя.`;
    confidence  = 0.60;
  }

  recs.push({
    apartment_id:        g.apartment_id,
    date_from:           g.date_from,
    date_to:             g.date_to,
    nights,
    current_price:       base,
    market_min:          marketMin,
    market_median:       marketMedian,
    market_avg:          marketAvg,
    market_max:          marketMax,
    recommended_price:   Math.round(recommended),
    recommendation_type: recType,
    reason,
    confidence,
    source:              'c1_rules',
    status:              'draft'
  });
}

if (recs.length === 0) {
  return [{ json: { _no_recs: true, message: 'No recommendations generated' } }];
}
return recs.map(r => ({ json: r }));
